/* eslint-disable camelcase */
import React, { useEffect, useState } from 'react';
import PropTypes from 'prop-types';
import { useDispatch } from 'react-redux';
import {
  ExpandableSection,
  Spinner,
  Label,
  EmptyState,
  EmptyStateBody,
  EmptyStateHeader,
} from '@patternfly/react-core';
import { Table, Thead, Tbody, Tr, Th, Td } from '@patternfly/react-table';
import { APIActions } from 'foremanReact/redux/API';
import { translate as __ } from 'foremanReact/common/I18n';

const JobInvocationLeappReport = ({ data = {} }) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [reportData, setReportData] = useState(null); // Stores the full detailed report
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);
  const dispatch = useDispatch();

  // 1. Guard Clause
  const isLeappJob = data?.template_name?.includes('Leapp') || 
                     data?.template_name?.includes('Preupgrade');

  if (!data || !data.id || !isLeappJob) return null;

  // 2. Fetch Logic (Chained Requests)
  useEffect(() => {
    if (isExpanded && !reportData && !isLoading && !error) {
      setIsLoading(true);
      
      // Step A: Find the Report ID associated with this job
      dispatch(
        APIActions.get({
          key: `GET_LEAPP_REPORT_LIST_${data.id}`,
          url: `/api/job_invocations/${data.id}/preupgrade_reports`,
          handleSuccess: (listResponse) => {
            const summary = listResponse.data?.results?.[0];
            
            if (summary?.id) {
              // Step B: Fetch the FULL report content using that ID
              dispatch(
                APIActions.get({
                  key: `GET_LEAPP_REPORT_DETAIL_${summary.id}`,
                  url: `/api/preupgrade_reports/${summary.id}`,
                  handleSuccess: (detailResponse) => {
                    // This response should contain the 'report_json' field
                    setReportData(detailResponse.data);
                    setIsLoading(false);
                  },
                  handleError: (err) => {
                    setError(err);
                    setIsLoading(false);
                  },
                })
              );
            } else {
              // No report found in the list
              setIsLoading(false);
            }
          },
          handleError: (err) => {
            setError(err);
            setIsLoading(false);
          },
        })
      );
    }
  }, [isExpanded, data.id, reportData, isLoading, error, dispatch]);

  const entries = reportData?.report_json?.entries || [];

  // 3. Render Helpers
  const renderSeverityLabel = (severity) => {
    switch (severity) {
      case 'high':
        return <Label color="red">{__('High')}</Label>;
      case 'medium':
        return <Label color="orange">{__('Medium')}</Label>;
      case 'low':
        return <Label color="blue">{__('Low')}</Label>;
      default:
        return <Label color="grey">{severity || __('Info')}</Label>;
    }
  };

  const renderRemediation = (remediation) => {
    if (!remediation) return '-';
    if (remediation.command) {
      return (
        <code
          style={{
            backgroundColor: '#f0f0f0',
            padding: '2px 4px',
            borderRadius: '4px',
            display: 'block',
            whiteSpace: 'pre-wrap',
            maxWidth: '400px',
            fontSize: '0.85em',
          }}
        >
          {remediation.command}
        </code>
      );
    }
    return remediation.text || '-';
  };

  return (
    <ExpandableSection
      toggleText={__('Leapp preupgrade report')}
      onToggle={(_event, val) => setIsExpanded(val)}
      isExpanded={isExpanded}
      className="leapp-report-section"
    >
      {isLoading && (
        <div style={{ padding: '20px', textAlign: 'center' }}>
          <Spinner size="md" />
        </div>
      )}

      {!isLoading && error && (
        <EmptyState variant="small">
          <EmptyStateHeader
            titleText={__('Could not fetch Leapp report')}
            headingLevel="h4"
          />
          <EmptyStateBody>
            {__('The report might not be generated yet, or an error occurred.')}
          </EmptyStateBody>
        </EmptyState>
      )}

      {!isLoading && !error && reportData && entries.length === 0 && (
        <EmptyState variant="small">
          <EmptyStateBody>{__('No issues found in the report.')}</EmptyStateBody>
        </EmptyState>
      )}

      {!isLoading && !error && entries.length > 0 && (
        <Table
          aria-label={__('Leapp Report Table')}
          variant="compact"
          borders={false}
        >
          <Thead>
            <Tr>
              <Th width={25}>{__('Title')}</Th>
              <Th width={10}>{__('Risk')}</Th>
              <Th width={10}>{__('Inhibitor')}</Th>
              <Th width={40}>{__('Remediation')}</Th>
            </Tr>
          </Thead>
          <Tbody>
            {entries.map((entry, index) => (
              <Tr key={index}>
                <Td dataLabel={__('Title')}>
                  <b>{entry.title}</b>
                  <div style={{ color: 'var(--pf-global--Color--200)', fontSize: '0.85em', marginTop: '4px' }}>
                    {entry.summary}
                  </div>
                </Td>
                <Td dataLabel={__('Risk')}>
                  {renderSeverityLabel(entry.severity)}
                </Td>
                <Td dataLabel={__('Inhibitor')}>
                  {entry.flags?.includes('inhibitor') ? (
                    <Label color="red" isCompact>
                      {__('Yes')}
                    </Label>
                  ) : (
                    __('No')
                  )}
                </Td>
                <Td dataLabel={__('Remediation')}>
                  {renderRemediation(entry.remediation)}
                </Td>
              </Tr>
            ))}
          </Tbody>
        </Table>
      )}
    </ExpandableSection>
  );
};

export default JobInvocationLeappReport;

JobInvocationLeappReport.propTypes = {
  data: PropTypes.shape({
    id: PropTypes.oneOfType([PropTypes.string, PropTypes.number]),
    template_name: PropTypes.string,
  }), // Removed .isRequired
};

JobInvocationLeappReport.defaultProps = {
  data: {}, // Add a default empty object
};
